# [doc = " Recursive walker for match arm comment assignment."] # [doc = " `depth` tracks how many `match` expressions we've entered; arm trailing comments in matches"] # [doc = " at depth > 1 (nested) are out of scope."] fn collect_match_arm_comments (item_idx : usize , expr : & Expr , remaining : & mut Vec < (u32 , String) > , arm_trailing : & mut HashMap < usize , HashMap < usize , String > > , fat_arrow_lines : & [u32] , depth : u32 ,) -> Result < () , FmtError > { match expr { Expr :: Match { scrutinee , arms } => { for (arm_idx , _arm) in arms . iter () . enumerate () { if remaining . is_empty () { break ; } let (arrow_line , comment_text) = remaining . remove (0) ; if ! fat_arrow_lines . contains (& arrow_line) { return Err (FmtError :: OutOfScope (format ! ("line {arrow_line}: internal error assigning arm comment (G2 never-silent)"))) ; } if depth > 0 { return Err (FmtError :: OutOfScope (format ! ("line {arrow_line}: a trailing comment on a nested match arm is out of scope \
                         for token-position anchoring (M-690 FLAG; see module doc); refused, never \
                         silently dropped (G2)"))) ; } arm_trailing . entry (item_idx) . or_default () . insert (arm_idx , comment_text) ; } for arm in arms { collect_match_arm_comments (item_idx , & arm . body , remaining , arm_trailing , fat_arrow_lines , depth + 1 ,) ? ; } collect_match_arm_comments (item_idx , scrutinee , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: Let { bound , body , .. } => { collect_match_arm_comments (item_idx , bound , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; collect_match_arm_comments (item_idx , body , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: If { cond , conseq , alt } => { collect_match_arm_comments (item_idx , cond , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; collect_match_arm_comments (item_idx , conseq , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; collect_match_arm_comments (item_idx , alt , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: For { xs , init , body , .. } => { collect_match_arm_comments (item_idx , xs , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; collect_match_arm_comments (item_idx , init , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; collect_match_arm_comments (item_idx , body , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: App { head , args } => { collect_match_arm_comments (item_idx , head , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; for a in args { collect_match_arm_comments (item_idx , a , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } } Expr :: WithParadigm { body , .. } | Expr :: Wild (body) | Expr :: Spore (body) | Expr :: Wrapping (body) | Expr :: Try (body) => { collect_match_arm_comments (item_idx , body , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: Consume (inner) => { collect_match_arm_comments (item_idx , inner , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: Swap { value , .. } => { collect_match_arm_comments (item_idx , value , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: Colony (hyphae) => { for h in hyphae { let Hypha { forage , body } = h ; if let Some (policy) = forage { collect_match_arm_comments (item_idx , policy , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } collect_match_arm_comments (item_idx , body , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } } Expr :: Ascribe (inner , _) => { collect_match_arm_comments (item_idx , inner , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: Lambda { body , .. } => { collect_match_arm_comments (item_idx , body , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: Fuse { left , right } => { collect_match_arm_comments (item_idx , left , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; collect_match_arm_comments (item_idx , right , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: Reclaim { policy , body } => { collect_match_arm_comments (item_idx , policy , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; collect_match_arm_comments (item_idx , body , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } Expr :: TupleLit (elems) => { for e in elems { collect_match_arm_comments (item_idx , e , remaining , arm_trailing , fat_arrow_lines , depth ,) ? ; } } Expr :: Lit (_) | Expr :: Path (_) => { } } Ok (()) }

