# [doc = " Render a `type` sum-type declaration in the readable style (M-974) — one constructor per line,"] # [doc = " break after each `|` — **only when** its compact single line would exceed [`READABLE_WIDTH`]."] # [doc = " Returns `None` when the compact form already fits (the caller then uses the compact render), so a"] # [doc = " short `type Result[A, E] = Ok(A) | Err(E);` stays inline. The output ends with the mandatory `;`"] # [doc = " terminator + newline, matching the compact item text (DN-57 §3)."] # [doc = ""] # [doc = " ```text"] # [doc = " type Predicate ="] # [doc = "     PAlways"] # [doc = "   | PSrcKindIs(Kind)"] # [doc = "   | PAnd(Predicate, Predicate);"] # [doc = " ```"] fn render_type_decl_readable (td : & mycelium_l1 :: ast :: TypeDecl) -> Option < String > { let vis = if td . vis . is_pub () { "pub " } else { "" } ; let params = if td . params . is_empty () { String :: new () } else { format ! ("[{}]" , td . params . join (", ")) } ; let ctors : Vec < String > = td . ctors . iter () . map (render_ctor) . collect () ; let compact_line = format ! ("{vis}type {}{} = {};" , td . name , params , ctors . join (" | ")) ; if compact_line . chars () . count () <= READABLE_WIDTH { return None ; } let mut lines : Vec < String > = Vec :: with_capacity (ctors . len ()) ; for (i , c) in ctors . iter () . enumerate () { if i == 0 { lines . push (format ! ("    {c}")) ; } else { lines . push (format ! ("  | {c}")) ; } } Some (format ! ("{vis}type {}{} =
{};
" , td . name , params , lines . join ("
"))) }

# [doc = " Render an expression, using multiline match rendering if the arm_map is non-empty and"] # [doc = " the expression (or sub-expression) is a match."] # [doc = ""] # [doc = " **Comma placement:** the arm separator `,` must go BEFORE any trailing comment on that arm's"] # [doc = " line.  A `// …` comment runs to end-of-line, so a comma placed AFTER it would be swallowed"] # [doc = " into the comment text and then lost when the output is re-lexed, breaking the round-trip."] # [doc = " Canonical multiline form:"] # [doc = " ```text"] # [doc = " match scrutinee {"] # [doc = "   pat0 => body0,  // comment"] # [doc = "   pat1 => body1"] # [doc = " }"] # [doc = " ```"] fn render_expr_with_arm_comments (e : & Expr , arm_map : & HashMap < usize , String > ,) -> Result < String , FmtError > { match e { Expr :: Match { scrutinee , arms } => { let scrutinee_str = render_expr_canonical_inner (scrutinee) ; let last_idx = arms . len () . saturating_sub (1) ; let mut arm_strs = Vec :: with_capacity (arms . len ()) ; for (arm_idx , arm) in arms . iter () . enumerate () { let arm_body = render_expr_canonical_inner (& arm . body) ; let pat = render_pattern (& arm . pattern) ; let is_last = arm_idx == last_idx ; let comma = if is_last { "" } else { "," } ; if let Some (cmt) = arm_map . get (& arm_idx) { arm_strs . push (format ! ("  {pat} => {arm_body}{comma}  {cmt}")) ; } else { arm_strs . push (format ! ("  {pat} => {arm_body}{comma}")) ; } } Ok (format ! ("match {scrutinee_str} {{
{}
}}" , arm_strs . join ("
"))) } _ => Ok (render_expr_canonical_inner (e)) , } }

